import React, { useEffect, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton, } from "@coreui/react";
import FormInput from '../../utils/FormInput';
import GoBackComponent from '../../utils/GoBackComponent';
import { validateEmail } from '../../utils/Common';
import { createSignUpCode } from '../../components/services/SignUpCodeApi';


function SignUpCodeForm(props) {
    const navigate = useNavigate();
    const { type } = props;
    const [email, setEmail] = useState();
    const [errors, setErrors] = useState({});
    const [errorMessage, setErrorMessage] = useState();

    const handleChange = (event) => {
        setEmail(event.target.value.trimStart());
    }

    const validateForm = () => {
        let errors = { name: "", position: "", description: "" };
        let formIsValid = true;
        if (!email) {
            errors['email'] = "Please enter email";
            formIsValid = false;
        }
        if(email && !validateEmail(email)) {
            errors['email'] = "Please enter a valid email address";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let postData = {
                email: email
            }
            let response = await createSignUpCode(postData);
            if(response?.message === "Success!") {
                navigate("/code");
            }
            if(response?.status === "409 CONFLICT") {
                setErrorMessage(response?.message);
            }
            setTimeout(() => {
                setErrorMessage("");
            }, 3000)
        }
    };

    return (
        <>
            <GoBackComponent goBackData={"code"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={8}>
                        <FormInput
                            value={email}
                            label={"Email"}
                            name={"email"}
                            onChange={handleChange}
                            required={true}
                            error={errors['email']}
                        />
                    </CCol>
                    {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
                    <CCol md={12}>
                        <CButton color="primary" onClick={handleSubmit} className="d-block">
                            {type === "CREATE" ? "Create" : "Update"}
                        </CButton>
                    </CCol>
                </CForm>
            </div>
        </>
    );
}

export default SignUpCodeForm;
